import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface RegionSales {
  region: string;
  sales: number;
}

interface SalesHeatmapData {
  totalSales: number;
  regions: RegionSales[];
}

export default function Widget() {
  const salesData = response.data as SalesHeatmapData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Total Sales
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              ${salesData.totalSales.toLocaleString()}
            </Typography>
          </Box>

          <PieChart
            height={200}
            series={[
              {
                data: salesData.regions.map((region) => ({
                  value: region.sales,
                  label: region.region,
                })),
                colors: ['#FFC107', '#FF5722', '#FF7043', '#FF8A65', '#FFAB91', '#FFCCBC'],
              },
            ]}
            legendPosition="left"
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiPieElement-root': {
                strokeWidth: 1,
                stroke: '#1E1E1E',
              },
              '& text': {
                fill: '#FFFFFF',
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
